<?php
namespace App\Domain\Repayments\Actions;
use App\Enums\InstallmentStatus;use App\Enums\LoanStatus;use App\Enums\RepaymentStatus;use App\Models\Loan;use App\Models\LoanRepayment;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class ReverseLoanRepayment{public function execute(LoanRepayment $repayment,string $reason):LoanRepayment{return DB::transaction(function()use($repayment,$reason){$repayment=LoanRepayment::query()->with('allocations')->lockForUpdate()->findOrFail($repayment->id);if($repayment->status!==RepaymentStatus::Successful||LoanRepayment::query()->where('reversal_of_id',$repayment->id)->exists())throw ValidationException::withMessages(['repayment'=>['This repayment cannot be reversed.']]);$loan=Loan::query()->lockForUpdate()->findOrFail($repayment->loan_id);$reversal=LoanRepayment::query()->create(['loan_id'=>$loan->id,'member_id'=>$repayment->member_id,'reversal_of_id'=>$repayment->id,'reference'=>'REV-'.strtoupper(Str::ulid()),'idempotency_key'=>'reversal-'.$repayment->id,'channel'=>$repayment->channel,'currency'=>$repayment->currency,'amount_minor'=>$repayment->allocated_minor,'allocated_minor'=>$repayment->allocated_minor,'unallocated_minor'=>0,'status'=>RepaymentStatus::Reversal,'received_at'=>now(),'recorded_by'=>Auth::id(),'notes'=>$reason]);foreach($repayment->allocations as $allocation){$installment=\App\Models\LoanRepaymentInstallment::query()->lockForUpdate()->findOrFail($allocation->loan_repayment_installment_id);$paidColumn=$allocation->component.'_paid_minor';$installment->{$paidColumn}=max(0,$installment->{$paidColumn}-$allocation->amount_minor);$installment->amount_paid_minor=max(0,$installment->amount_paid_minor-$allocation->amount_minor);$installment->status=$installment->due_date->isPast()?InstallmentStatus::Overdue:InstallmentStatus::Upcoming;$installment->save();$reversal->allocations()->create(['loan_repayment_installment_id'=>$installment->id,'component'=>$allocation->component,'amount_minor'=>$allocation->amount_minor]);}$hasOverdue=$loan->installments()->where('status',InstallmentStatus::Overdue->value)->exists();$loan->update(['outstanding_minor'=>$loan->outstanding_minor+$repayment->allocated_minor,'status'=>$hasOverdue?LoanStatus::InArrears:LoanStatus::Active]);$repayment->update(['status'=>RepaymentStatus::Reversed,'reversed_at'=>now(),'reversed_by'=>Auth::id(),'reversal_reason'=>$reason]);return $reversal->load('allocations');});}}
